const body = $json.body ?? {};
const taskId = $json.params?.id;
const statuses = ['todo','in_progress','done'];
const priorities = ['low','medium','high','urgent'];

if (!taskId) return [{ json: { statusCode: 400, body: { message: 'id is required' }, _stop: true } }];

const patch = {};
if (body.title !== undefined) patch.title = String(body.title).trim().slice(0, 200);
if (body.description !== undefined) patch.description = body.description ?? null;
if (body.status !== undefined) {
  if (!statuses.includes(body.status)) return [{ json: { statusCode: 400, body: { message: 'invalid status' }, _stop: true } }];
  patch.status = body.status;
}
if (body.priority !== undefined) {
  if (!priorities.includes(body.priority)) return [{ json: { statusCode: 400, body: { message: 'invalid priority' }, _stop: true } }];
  patch.priority = body.priority;
}
if (body.estimate !== undefined) {
  if (body.estimate === null || body.estimate === '') patch.estimate = null;
  else {
    const n = Number(body.estimate);
    if (Number.isNaN(n) || n < 0) return [{ json: { statusCode: 400, body: { message: 'estimate must be a non-negative number' }, _stop: true } }];
    patch.estimate = n;
  }
}
if (body.parent_id !== undefined) patch.parent_id = body.parent_id ?? null;

if (Object.keys(patch).length === 0) return [{ json: { statusCode: 400, body: { message: 'empty patch' }, _stop: true } }];

return [{ json: { _stop: false, taskId, patch } }];
